class Solution:
    def decodeString(self, s):
        # recursive-descent parser as an independent construction
        self.i = 0
        def parse():
            result = ''
            num = 0
            while self.i < len(s):
                ch = s[self.i]
                if ch.isdigit():
                    num = num * 10 + int(ch)
                    self.i += 1
                elif ch == '[':
                    self.i += 1
                    inner = parse()
                    result += inner * num
                    num = 0
                elif ch == ']':
                    self.i += 1
                    return result
                else:
                    result += ch
                    self.i += 1
            return result
        return parse()

