var decodeString = function(s) {
    const stack = [];
    let cur = '';
    let num = 0;
    for (const ch of s) {
        if (ch >= '0' && ch <= '9') {
            num = num * 10 + (ch.charCodeAt(0) - 48);
        } else if (ch === '[') {
            stack.push([cur, num]);
            cur = '';
            num = 0;
        } else if (ch === ']') {
            const [prev, k] = stack.pop();
            cur = prev + cur.repeat(k);
        } else {
            cur += ch;
        }
    }
    return cur;
};
